mapper.select:
SELECT

FROM toc_clinical_transfer
WHERE tenant_id = #{tenantId}
  AND id = #{id}

SELECT

FROM toc_clinical_transfer
WHERE tenant_id = #{tenantId}
  AND response_id = #{responseId}
ORDER BY id DESC

SELECT

FROM toc_clinical_transfer
WHERE tenant_id = #{tenantId}
  AND patient_id = #{patientId}
ORDER BY id DESC

mapper.update:
UPDATE toc_clinical_transfer
SET response_id = #{responseId},
    patient_id = #{patientId},
    transfer_status = #{transferStatus},
    approved_by = #{approvedBy},
    approved_at = #{approvedAt},
    transfer_note = #{transferNote}
WHERE tenant_id = #{tenantId}
  AND id = #{id}

mapper.delete:
DELETE
FROM toc_clinical_transfer
WHERE tenant_id = #{tenantId}
  AND id = #{id}
